async function refreshSections(sectionIds = ['cart-drawer', 'cart-icon-bubble']) {
  const params = new URLSearchParams({ sections: sectionIds.join(',') });
  const response = await fetch(`/?${params.toString()}`);
  const html = await response.json();

  sectionIds.forEach((id) => {
    const container = document.getElementById(`shopify-section-${id}`);
    if (container && html[id]) container.outerHTML = html[id];
  });
}

