const bus = new EventTarget();

export function publish(name, detail = {}) {
  bus.dispatchEvent(new CustomEvent(name, { detail }));
}

export function subscribe(name, callback) {
  const handler = (event) => callback(event.detail);
  bus.addEventListener(name, handler);
  return () => bus.removeEventListener(name, handler);
}

async function updateCartAndUI(line, quantity) {
  document.documentElement.classList.add('is-cart-loading');
  try {
    await fetch('/cart/change.js', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ line, quantity, sections: 'cart-drawer,cart-icon-bubble' })
    });
    publish('cart:updated');
    await refreshSections(['cart-drawer', 'cart-icon-bubble']);
  } finally {
    document.documentElement.classList.remove('is-cart-loading');
  }
}

import { useShopQuery, gql } from '@shopify/hydrogen';

